module binary_counter(CLK,RST,EN,COUNT);
input CLK,RST,EN;
output [3:0] COUNT;
reg [3:0] COUNT;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge CLK or posedge RST or posedge dbg_halt) begin
	if (RST)
		COUNT <= 0;
	else if (EN)
		COUNT <= COUNT + 1;
	else
		COUNT <= COUNT;
end

endmodule
